#include<bits/stdc++.h>
using namespace std;
const int N=5050;
int n,m;
int scc[N],scccnt,dfncnt,dfn[N],low[N];
bool instk[N];
stack<int> s;
vector<int> mp[N],v[N];
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=1;
    s.push(x);
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        int top;
        scccnt++;
        do
        {
            top=s.top();
            s.pop();
            instk[top]=0;
            v[scccnt].push_back(top);
            scc[top]=scccnt;
        }while(top!=x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int a,b,t;
        scanf("%d%d%d",&a,&b,&t);
        mp[a].push_back(b);
        if(t==2)
        {
            mp[b].push_back(a);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=scccnt;i++)
    {
        sort(v[i].begin(),v[i].end());
    }
    int max1=0,max2,max3;
    for(int i=1;i<=scccnt;i++)
    {
        int siz=v[i].size();
        if(siz>max1)
        {
            max1=siz;
            max2=v[i][0];
            max3=i;
        }
        else if(siz==max1&&v[i][0]<max2)
        {
            max2=v[i][0];
            max3=i;
        }
    }
    printf("%d\n",max1);
    for(int i:v[max3])
    {
        printf("%d ",i);
    }
    return 0;
}
